/* ============================================================================
   LEARN TAB — pattern recognition based on Goulet et al. 2026 Fig. 3
   ============================================================================ */

/** Mock scatterplot illustrating one canonical pattern. Points are
    pre-computed in [0, 1]² (already in "log space" — i.e. position on
    the plot, not raw abundance). Axis range spans 1e-6 to 1e-1 (five
    decades, 0.2 coord units per decade) so very-low-abundance signals
    have visible room. */
const PatternMiniPlot = ({
  points,
  highlightPoints = [],
  rate = null,
  lineSide = "below", // "below" (line under y=x, X is source) or "above" (line over y=x, Y is source)
  diagonal = true,
  height = 170,
  width = 200,
}) => {
  // Asymmetric padding: more room on the left (rotated "target" label +
  // tick labels) and bottom (tick labels + "source" label).
  const padL = 30;
  const padR = 8;
  const padT = 8;
  const padB = 28;
  const w = width - padL - padR;
  const h = height - padT - padB;
  const toX = (x) => padL + x * w;
  const toY = (y) => padT + (1 - y) * h;
  // Log tick positions along each axis: coord 0 = 1e-6, coord 1 = 1e-1.
  // Three labels at every-other-decade match the paper figure: 1e-6,
  // 1e-4, 1e-2 (1e-1 is the implicit upper edge).
  const ticks = [0, 0.4, 0.8];
  const tickLabels = ["1e-6", "1e-4", "1e-2"];
  // Coord offset corresponding to log10(rate). Each decade is 0.2 coord
  // units (5 decades over the [0, 1] range). Multiplying log10(rate)
  // (negative) by 0.2 gives a negative shift to apply to either x or y
  // (depending on lineSide) — the contamination line appears on the
  // side of y=x where the source sample's axis is.
  const lineOffset =
    rate && rate > 0 && rate < 1 ? Math.log10(rate) * 0.2 : null;
  return (
    <svg
      width={width}
      height={height}
      viewBox={`0 0 ${width} ${height}`}
      style={{ background: "var(--bg-card)", borderRadius: 3 }}
    >
      {/* Faint gridlines — match the main Scatterplot's #eee */}
      {ticks.map((t, i) => (
        <line
          key={`gx-${i}`}
          x1={toX(t)}
          y1={padT}
          x2={toX(t)}
          y2={padT + h}
          stroke="#eee"
          strokeWidth={0.5}
        />
      ))}
      {ticks.map((t, i) => (
        <line
          key={`gy-${i}`}
          x1={padL}
          y1={toY(t)}
          x2={padL + w}
          y2={toY(t)}
          stroke="#eee"
          strokeWidth={0.5}
        />
      ))}
      {/* Axes — deep teal #275662, matching the main Scatterplot */}
      <line x1={padL} y1={padT + h} x2={padL + w} y2={padT + h} stroke="#275662" strokeWidth={1} />
      <line x1={padL} y1={padT} x2={padL} y2={padT + h} stroke="#275662" strokeWidth={1} />
      {/* y = x diagonal — theme-neutral mid-grey #7d8b91 so it stays
         readable in both light and dark mode (pure black disappeared on
         the dark background). Matches the gallery card's identity line. */}
      {diagonal && (
        <line
          x1={toX(0)}
          y1={toY(0)}
          x2={toX(1)}
          y2={toY(1)}
          stroke="#7d8b91"
          strokeWidth={1}
          strokeDasharray="2 4"
          opacity={0.75}
        />
      )}
      {/* Contamination line. Drawn parallel to y = x but shifted by
         log10(rate). The lineSide indicates on which side of y = x
         the source-only species accumulate:
         - "below": source on X axis, line falls below y = x
         - "above": source on Y axis, line falls above y = x
         Each scatterplot shows ONE direction of contamination only —
         a bidirectional pair appears in the events table as two
         separate events, each with its own plot.
         Style matches the main Scatterplot: salmon, dashed 5 3, w 1.5. */}
      {lineOffset !== null && lineSide === "below" && (
        <line
          x1={toX(-lineOffset)}
          y1={toY(0)}
          x2={toX(1)}
          y2={toY(1 + lineOffset)}
          stroke="#ed6e6c"
          strokeWidth={1.5}
          strokeDasharray="5 3"
        />
      )}
      {lineOffset !== null && lineSide === "above" && (
        <line
          x1={toX(0)}
          y1={toY(-lineOffset)}
          x2={toX(1 + lineOffset)}
          y2={toY(1)}
          stroke="#ed6e6c"
          strokeWidth={1.5}
          strokeDasharray="5 3"
        />
      )}
      {/* Regular points — coords already in the [0,1]² axis space
          (1e-6..1e-1 per decade × 5). Mid-grey #7d8b91 (matching the
          main Scatterplot) so they stay visible against both the light
          and dark theme card backgrounds. */}
      {points.map(([x, y], i) => (
        <circle
          key={`p-${i}`}
          cx={toX(x)}
          cy={toY(y)}
          r={2}
          fill="#7d8b91"
          fillOpacity={0.55}
        />
      ))}
      {/* Highlighted points (e.g. cluster of interest) */}
      {highlightPoints.map(([x, y], i) => (
        <circle
          key={`h-${i}`}
          cx={toX(x)}
          cy={toY(y)}
          r={2.2}
          fill="#ed6e6c"
          stroke="var(--bg-card)"
          strokeWidth={0.6}
        />
      ))}
      {/* Tick labels — positioned just outside the data area, leaving
          room for the axis labels further out. */}
      {ticks.map((t, i) => (
        <text
          key={`tx-${i}`}
          x={toX(t)}
          y={padT + h + 10}
          textAnchor="middle"
          fontSize={7}
          fill="#797870"
          style={{ fontFamily: "ui-monospace, monospace" }}
        >
          {tickLabels[i]}
        </text>
      ))}
      {ticks.map((t, i) => (
        <text
          key={`ty-${i}`}
          x={padL - 4}
          y={toY(t) + 2}
          textAnchor="end"
          fontSize={7}
          fill="#797870"
          style={{ fontFamily: "ui-monospace, monospace" }}
        >
          {tickLabels[i]}
        </text>
      ))}
      {/* Axis labels — at the very edge of the SVG, beyond the tick
          labels so they don't overlap. */}
      <text
        x={padL + w / 2}
        y={height - 3}
        textAnchor="middle"
        fontSize={8}
        fill="#5a5550"
        style={{ fontFamily: "ui-monospace, monospace" }}
      >
        source
      </text>
      <text
        x={9}
        y={padT + h / 2}
        textAnchor="middle"
        fontSize={8}
        fill="#5a5550"
        transform={`rotate(-90, 9, ${padT + h / 2})`}
        style={{ fontFamily: "ui-monospace, monospace" }}
      >
        target
      </text>
    </svg>
  );
};

/** Single pattern reference card. Header strip carries the verdict
    color, then the body shows the mini-plot, a description, signals
    to look for, and an optional "watch out" warning. */
const PatternCard = ({
  caseLabel,
  title,
  verdict,
  rate,
  probability,
  introduced,
  plot,
  description,
  signals,
  watchOut,
}) => {
  // The header strip's color and label depend on the verdict. The
  // FP_OR_UNCERTAIN tone is reserved for borderline cases where the
  // paper classifies them as FP but a stricter curator might reasonably
  // tag them as Uncertain instead. Drawn as a gradient from salmon to
  // grey to signal "could go either way".
  const tone =
    verdict === "TP"
      ? { bg: "#00a3a6", text: "True positive" }
      : verdict === "FP"
        ? { bg: "#ed6e6c", text: "False positive" }
        : verdict === "FP_OR_UNCERTAIN"
          ? {
              bg: "linear-gradient(90deg, #ed6e6c 0%, #c4c0b3 100%)",
              text: "False positive / Uncertain",
            }
          : verdict === "FN"
            ? { bg: "#9dc544", text: "False negative — missed" }
            : { bg: "var(--border-strong)", text: "Uncertain" };
  return (
    <div
      style={{
        border: "1px solid var(--border)",
        borderRadius: 4,
        background: "var(--bg-card)",
        overflow: "hidden",
        display: "flex",
        flexDirection: "column",
      }}
    >
      <div
        style={{
          background: tone.bg,
          color: "#fff",
          padding: "8px 14px",
          fontSize: 10,
          fontWeight: 700,
          letterSpacing: "0.05em",
          textTransform: "uppercase",
          fontFamily: '"Raleway", sans-serif',
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          gap: 6,
        }}
      >
        <span>{tone.text}</span>
      </div>
      <div className="p-4" style={{ flex: 1 }}>
        <h3
          style={{
            fontSize: 14,
            fontWeight: 700,
            color: "var(--ink)",
            marginBottom: 4,
            fontFamily: '"Raleway", sans-serif',
            lineHeight: 1.3,
          }}
        >
          {title}
        </h3>
        {(rate || probability || introduced) && (
          <div
            style={{
              fontSize: 11,
              color: "var(--ink-muted)",
              marginBottom: 10,
              fontFamily: "ui-monospace, monospace",
            }}
          >
            {rate && <>rate&nbsp;=&nbsp;{rate}</>}
            {rate && (probability || introduced) && " · "}
            {probability && <>p&nbsp;=&nbsp;{probability}</>}
            {probability && introduced && " · "}
            {introduced && <>intro&nbsp;=&nbsp;{introduced}</>}
          </div>
        )}
        <div className="mb-3" style={{ display: "flex", justifyContent: "center" }}>
          {plot}
        </div>
        <div
          style={{
            fontSize: 12,
            color: "var(--ink-soft)",
            lineHeight: 1.55,
            marginBottom: 12,
          }}
        >
          {description}
        </div>
        <div
          className="mt-3 pt-3"
          style={{ borderTop: "1px solid var(--border-soft)" }}
        >
          <div
            style={{
              fontSize: 9,
              letterSpacing: "0.1em",
              textTransform: "uppercase",
              color: "#00a3a6",
              fontWeight: 700,
              marginBottom: 4,
              fontFamily: '"Raleway", sans-serif',
            }}
          >
            Signals to spot
          </div>
          <ul
            className="list-disc pl-5 text-[12px]"
            style={{ color: "var(--ink-soft)", lineHeight: 1.55 }}
          >
            {signals.map((s, i) => (
              <li key={i}>{s}</li>
            ))}
          </ul>
        </div>
        {watchOut && (
          <div
            className="mt-3 pt-3"
            style={{ borderTop: "1px solid var(--border-soft)" }}
          >
            <div
              style={{
                fontSize: 9,
                letterSpacing: "0.1em",
                textTransform: "uppercase",
                color: "#ed6e6c",
                fontWeight: 700,
                marginBottom: 4,
                fontFamily: '"Raleway", sans-serif',
              }}
            >
              Watch out
            </div>
            <p style={{ fontSize: 12, color: "var(--ink-soft)", lineHeight: 1.55 }}>
              {watchOut}
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

/* ----- Real scatterplot data from Goulet et al. 2026 Fig. 3 -----
   ===================================================================
   These are the actual species-abundance pairs from the paper's
   reference figure. Each point's coordinates ARE the paper's axis
   choices: X = bottom-labelled sample, Y = left-labelled sample.
   This means the plots reproduce the paper visually without
   re-orientation, so a reader can cross-reference directly.

   Consequence: the contamination line falls ABOVE y = x for cases
   where the paper put the source on the Y axis (A, C, D, F) and
   BELOW y = x for cases where the paper put the source on the X
   axis (B). Each card passes `lineSide="above"` or `"below"`
   accordingly so the contamination line is drawn on the correct
   side. Cases without a clearly identifiable line (E, G, H, plus
   all FN cases) get no line.

   Pairs (X axis / bottom label → Y axis / left label):
     A: ERS848718 → ERS848719              (TP, rate 0.49%, BIDIRECTIONAL — two lines)
     B: ERS475279 → ERS475376              (TP, rate 1.18%, single line above y=x)
     C: ERS475396_ERS475397 → ERS475230    (TP, rate 7.14%, line above)
     D: ERS475139 → ERS475245_ERS475246    (TP, rate 32%, line above)
     E: ERS1066649 → ERS1066724            (FP, p=0.52)
     F: ERS475399 → ERS475353              (FP, rate 2.58%, line above)
     G: ERS475307 → ERS475305              (FP, p=0.70)
     H: ERS848646 → ERS848634              (FP, p=1.00 misleading)
     I: ERS475239 → ERS475189              (FN)
     J: ERS475154_ERS475155 → ERS475389_ERS475390  (FN)
     K: ERS475410_ERS475411 → ERS475231    (FN, cascade)
     L: ERS848634 → ERS848623              (FN, clear line missed) */

