  const TAB_HASH_ALIASES = {
    overview: "overview",
    samples: "samples",
    sample: "samples",
    events: "table",
    table: "table",
    scatter: "scatter",
    scatterplots: "scatter",
    scatterplot: "scatter",
    validate: "validate",
    validation: "validate",
    network: "network",
    plate: "plate",
    "plate-map": "plate",
    export: "export",
    datasets: "datasets",
    learn: "learn",
    help: "help",
  };
