  // over their shoulder) sees which study they're working on. Auto-set
  // when a bundled dataset is loaded; "Untitled analysis" by default
  // for user uploads. Editable inline; persisted in the session JSON.
  const [analysisTitle, setAnalysisTitle] = useState(
    initial?.analysisTitle || "",
  );
  // Draft state for the "Explore new pairs" sub-tab of the Scatter tab.
  // Lifted to App level so the form values survive tab switches —
  // dropping it inside ScatterTab would lose everything every time the
  // curator hops to e.g. Events to verify a sample name.
  const EXPLORE_PAIRS_DEFAULTS = {
    src: "",
    tgt: "",
    rateLog: -2,
    probability: 0.9,
    verdict: "true_positive",
    targetVerdict: "contaminated",
    action: "suppress",
    notes: "Manually added by user",
  };
  const [explorePairsForm, setExplorePairsForm] = useState(
    EXPLORE_PAIRS_DEFAULTS,
  );
  // "Color contamination-line points" toggle — lifted to App so the
  // curator's choice survives Scatter ↔ Validate ↔ other-tab
  // round-trips (otherwise the state would reset every time the tab
  // unmounts). Defaults to OFF so the curator first sees the raw
  // scatter shape; they can opt in to the model's red points anywhere
  // the toggle exists.
  const [colorOnLine, setColorOnLine] = useState(false);
  // Samples-tab UI state — lifted to App so sort order, page,
  // context filters, expanded notes and scroll position survive a
  // round-trip to the Scatter / Events tabs (otherwise drilling on a
  // sample dropped the curator back at the top of the table). Held
  // in a ref so the SamplesTab can keep using local useState
  // internally; values are synced into / out of the ref on mount
  // and on every change.
  const samplesUIRef = useRef({
    sortBy: "rate",
    sortDir: "desc",
    page: 1,
    openNotes: [],
    subjectFilter: null,
    timepointFilter: null,
    groupFilter: null,
    biomeFilter: null,
    controlFilter: "any",
    lowBiomassFilter: "any",
    lowSeqDepthFilter: "any",
    scrollY: 0,
  });
  // Network tab colour scheme — lifted to App so the user's choice
  // ("exploration" vs "curation") survives switching tabs and coming
  // back to Network.
  const [networkColorScheme, setNetworkColorScheme] = useState("exploration");
  // Global config dialog — accessible from the header gear button on
  // every page. Body is currently a placeholder; populate as we
  // surface user-tunable settings.
  const [configOpen, setConfigOpen] = useState(false);
  // Konami easter egg — ↑ ↑ ↓ ↓ ← → ← → B A unlocks the Croc Arcade.
  const [arcadeOpen, setArcadeOpen] = useState(false);
  useKonamiCode(() => setArcadeOpen(true));
  // In-browser CroCoDeEL run page — opened from the events upload
